import fs from 'node:fs';
import path from 'node:path';
import { Readable } from 'node:stream';
import tar from 'tar';

export function extractTarGzStream(
  sourceStream: Readable,
  destinationPath: string,
  subdomain: string
): Promise<void> {
  const tempDir = path.join(destinationPath, '.tmp');
  const temp = fs.mkdtempSync(tempDir);
  const res = new Promise<void>((resolve, reject) => {
    sourceStream
      .pipe(tar.extract({ cwd: temp }))
      .on('finish', () => {
        const files = fs.readdirSync(temp) as [string, ...string[]];
        const index = files.findIndex((filePath) => !filePath.startsWith('._'));
        const currDir = path.join(temp, files[index > -1 ? index : 0] ?? files[0]);
        const newDir = path.join(destinationPath, subdomain);
        if (fs.existsSync(newDir)) {
          fs.rmSync(newDir, { recursive: true, force: true });
        }
        fs.renameSync(currDir, newDir);
        fs.rmSync(temp, { recursive: true, force: true });
        resolve();
      })
      .on('error', (err) => reject(err));
  });
  return res;
}
